/**
 * @param {number[]} nums
 * @param {number[][]} queries
 * @return {number[]}
 */
function solve(nums, queries) {
    const results = [];
    const MAX_VAL = 2 * 10**14; // A sufficiently large upper bound for binary search

    for (const query of queries) {
        const [l, r, k] = query;

        // 1. Identify all positive even numbers in nums[l..r]
        const removedEvens = new Set();
        for (let i = l; i <= r; i++) {
            const num = nums[i];
            if (num % 2 === 0) {
                removedEvens.add(num);
            }
        }

        // 2. Binary Search for the answer 'X'
        // The answer X is the k-th smallest positive even number not in removedEvens.
        // We are looking for the smallest even number X such that:
        // (Count of positive even numbers <= X) - (Count of removed evens <= X) >= k

        let low = 2; // Smallest positive even number
        let high = 2 * 10**9 + 100; // A safe upper bound, since nums[i] <= 10^9, and k can be up to 10^9, the answer can be larger, but let's estimate a safe upper bound.
                                     // If k=10^9 and no evens are removed, the answer is 2*10^9. If many evens are removed, it might be larger.
                                     // Since nums[i] <= 10^9, the count of removed evens is at most 10^5. 
                                     // If we need the 10^9-th remaining even number, it will be roughly 2 * (10^9 + 10^5), which is around 2*10^9.
                                     // Let's use a generous bound like 3 * 10^9 or slightly more robustly, based on k.
                                     // The k-th remaining even number is roughly 2 * (k + |removedEvens|). Max k is 10^9, max removedEvens is 10^5. Max answer ~ 2 * 10^9.
        high = 4 * 10**9; // Safe upper bound for the answer

        let ans = high;

        while (low <= high) {
            const mid = Math.floor((low + high) / 2);

            // The candidate answer 'mid' must be even. If mid is odd, we adjust it.
            let candidate;
            if (mid % 2 !== 0) {
                candidate = mid + 1;
            } else {
                candidate = mid;
            }

            // Count of positive even numbers <= candidate
            // Even numbers are 2, 4, 6, ..., 2*M. The count is M = floor(candidate / 2).
            const totalEvens = Math.floor(candidate / 2);

            // Count of removed evens <= candidate
            let removedCount = 0;
            for (const e of removedEvens) {
                if (e <= candidate) {
                    removedCount++;
                }
            }

            const remainingCount = totalEvens - removedCount;

            if (remainingCount >= k) {
                // 'candidate' might be the answer, or we can find a smaller one.
                ans = candidate;
                high = mid - 1;
            } else {
                // 'candidate' is too small, we need a larger number.
                low = mid + 1;
            }
        }

        results.push(ans);
    }

    return results;
}

